<script>
(function() {
  'use strict';

  // ─── COIN RENDERER ────────────────────────────────────────────────
  const HERO = document.getElementById('coin-hero');
  const ctx = HERO.getContext('2d');

  let W, H;
  function resizeHero() {
    const rect = HERO.getBoundingClientRect();
    const dpr = window.devicePixelRatio || 1;
    W = Math.floor(rect.width * dpr);
    H = Math.floor(rect.height * dpr);
    HERO.width = W;
    HERO.height = H;
  }
  resizeHero();

  // Edition canvases
  const editionCanvases = document.querySelectorAll('.edition-canvas');
  function resizeEditions() {
    editionCanvases.forEach(c => {
      const rect = c.getBoundingClientRect();
      const dpr = window.devicePixelRatio || 1;
      const s = Math.min(rect.width, 300) * dpr;
      c.width = s;
      c.height = s;
    });
  }
  resizeEditions();

  // ─── 3D MATH ──────────────────────────────────────────────────────
  function rotateY(px, py, pz, a) {
    const c = Math.cos(a), s = Math.sin(a);
    return [c*px + s*pz, py, -s*px + c*pz];
  }
  function rotateX(px, py, pz, a) {
    const c = Math.cos(a), s = Math.sin(a);
    return [px, c*py - s*pz, s*py + c*pz];
  }

  // ─── COIN GEOMETRY ────────────────────────────────────────────────
  const RADIUS = 1.0;
  const THICKNESS = 0.08;
  const REEDE_COUNT = 48;
  const FACE_SEGMENTS = 64;

  function generateCoinGeometry() {
    const points = []; // [x,y,z]
    const frontFaceIndices = [];
    const backFaceIndices = [];
    const edgeIndices = []; // pairs of indices for reedes

    // Front face center
    const fcIdx = points.length;
    points.push([0, 0, RADIUS * THICKNESS / 2]);

    // Front face ring
    const frontRingStart = points.length;
    for (let i = 0; i < FACE_SEGMENTS; i++) {
      const a = (i / FACE_SEGMENTS) * Math.PI * 2;
      points.push([Math.cos(a) * RADIUS, Math.sin(a) * RADIUS, RADIUS * THICKNESS / 2]);
    }

    // Back face ring
    const backRingStart = points.length;
    for (let i = 0; i < FACE_SEGMENTS; i++) {
      const a = (i / FACE_SEGMENTS) * Math.PI * 2;
      points.push([Math.cos(a) * RADIUS, Math.sin(a) * RADIUS, -RADIUS * THICKNESS / 2]);
    }

    // Back face center
    const bcIdx = points.length;
    points.push([0, 0, -RADIUS * THICKNESS / 2]);

    // Front face triangles (center + ring)
    for (let i = 0; i < FACE_SEGMENTS; i++) {
      const next = (i + 1) % FACE_SEGMENTS;
      frontFaceIndices.push([fcIdx, frontRingStart + i, frontRingStart + next]);
    }

    // Back face triangles (center + ring, reversed winding)
    for (let i = 0; i < FACE_SEGMENTS; i++) {
      const next = (i + 1) % FACE_SEGMENTS;
      backFaceIndices.push([bcIdx, backRingStart + next, backRingStart + i]);
    }

    // Edge reedes
    for (let i = 0; i < REEDE_COUNT; i++) {
      const a = (i / REEDE_COUNT) * Math.PI * 2;
      const r = RADIUS * 1.01;
      const topIdx = points.length;
      points.push([Math.cos(a) * r, Math.sin(a) * r, RADIUS * THICKNESS / 2]);
      const botIdx = points.length;
      points.push([Math.cos(a) * r, Math.sin(a) * r, -RADIUS * THICKNESS / 2]);
      edgeIndices.push([topIdx, botIdx]);
    }

    return { points, frontFaceIndices, backFaceIndices, edgeIndices };
  }

  const coinGeo = generateCoinGeometry();

  // ─── FACE TEXTURE RENDERING (offscreen canvas) ──────────────────
  function renderFaceTexture(faceType, size) {
    const c = document.createElement('canvas');
    c.width = c.height = size;
    const cx2 = c.getContext('2d');
    const s = size;
    const cx3 = s / 2, cy3 = s / 2;

    if (faceType === 'front') {
      // Emblem background circle
      cx2.save();
      cx2.beginPath();
      cx2.arc(cx3, cy3, s * 0.42, 0, Math.PI * 2);
      cx2.fillStyle = 'rgba(0,0,0,0.15)';
      cx2.fill();

      // Outer ring
      cx2.beginPath();
      cx2.arc(cx3, cy3, s * 0.44, 0, Math.PI * 2);
      cx2.strokeStyle = 'rgba(0,0,0,0.3)';
      cx2.lineWidth = s * 0.015;
      cx2.stroke();

      // Inner ring
      cx2.beginPath();
      cx2.arc(cx3, cy3, s * 0.38, 0, Math.PI * 2);
      cx2.strokeStyle = 'rgba(0,0,0,0.2)';
      cx2.lineWidth = s * 0.008;
      cx2.stroke();

      // WastedToken text
      cx2.fillStyle = 'rgba(0,0,0,0.55)';
      cx2.font = `bold ${s * 0.11}px Georgia, serif`;
      cx2.textAlign = 'center';
      cx2.textBaseline = 'middle';
      cx2.fillText('WASTED', cx3, cy3 - s * 0.1);

      // Token text
      cx2.font = `bold ${s * 0.14}px Georgia, serif`;
      cx2.fillText('TOKEN', cx3, cy3 + s * 0.06);

      // Mint text
      cx2.font = `${s * 0.055}px Georgia, serif`;
      cx2.fillStyle = 'rgba(0,0,0,0.4)';
      cx2.fillText('MINT', cx3, cy3 + s * 0.18);

      // Decorative stars
      for (let i = 0; i < 6; i++) {
        const a = (i / 6) * Math.PI * 2 - Math.PI / 2;
        const sx = cx3 + Math.cos(a) * s * 0.3;
        const sy = cy3 + Math.sin(a) * s * 0.3;
        drawStar(cx2, sx, sy, s * 0.025, s * 0.01);
      }

      // Top arc text
      cx2.font = `${s * 0.04}px Georgia, serif`;
      cx2.fillStyle = 'rgba(0,0,0,0.3)';
      cx2.fillText('— EST. 2024 —', cx3, cy3 - s * 0.28);

      // Bottom arc text
      cx2.fillText('PHYSICAL • TANGIBLE', cx3, cy3 + s * 0.3);

      cx2.restore();
    } else {
      // Back face - denomination
      cx2.save();
      cx2.beginPath();
      cx2.arc(cx3, cy3, s * 0.42, 0, Math.PI * 2);
      cx2.fillStyle = 'rgba(0,0,0,0.1)';
      cx2.fill();

      // Outer ring
      cx2.beginPath();
      cx2.arc(cx3, cy3, s * 0.44, 0, Math.PI * 2);
      cx2.strokeStyle = 'rgba(0,0,0,0.3)';
      cx2.lineWidth = s * 0.015;
      cx2.stroke();

      // Inner ring
      cx2.beginPath();
      cx2.arc(cx3, cy3, s * 0.40, 0, Math.PI * 2);
      cx2.strokeStyle = 'rgba(0,0,0,0.15)';
      cx2.lineWidth = s * 0.006;
      cx2.stroke();

      // Denomination
      cx2.fillStyle = 'rgba(0,0,0,0.55)';
      cx2.font = `bold ${s * 0.18}px Georgia, serif`;
      cx2.textAlign = 'center';
      cx2.textBaseline = 'middle';
      cx2.fillText('10,000', cx3, cy3 - s * 0.08);

      // TOKENS
      cx2.font = `bold ${s * 0.1}px Georgia, serif`;
      cx2.fillText('TOKENS', cx3, cy3 + s * 0.1);

      // Value text
      cx2.font = `${s * 0.045}px Georgia, serif`;
      cx2.fillStyle = 'rgba(0,0,0,0.35)';
      cx2.fillText('ONE TEN THOUSAND', cx3, cy3 + s * 0.24);

      // Decorative dots
      for (let i = 0; i < 12; i++) {
        const a = (i / 12) * Math.PI * 2;
        const dx = cx3 + Math.cos(a) * s * 0.35;
        const dy = cy3 + Math.sin(a) * s * 0.35;
        cx2.beginPath();
        cx2.arc(dx, dy, s * 0.01, 0, Math.PI * 2);
        cx2.fillStyle = 'rgba(0,0,0,0.25)';
        cx2.fill();
      }

      // Top/bottom text
      cx2.font = `${s * 0.04}px Georgia, serif`;
      cx2.fillText('• DENOMINATION •', cx3, cy3 - s * 0.3);
      cx2.fillText('WASTEDTOKEN MINT', cx3, cy3 + s * 0.35);

      cx2.restore();
    }
    return c;
  }

  function drawStar(ctx2, x, y, r, lineWidth) {
    ctx2.beginPath();
    for (let i = 0; i < 5; i++) {
      const a1 = (i / 5) * Math.PI * 2 - Math.PI / 2;
      const a2 = ((i + 0.5) / 5) * Math.PI * 2 - Math.PI / 2;
      if (i === 0) ctx2.moveTo(x + Math.cos(a1) * r, y + Math.sin(a1) * r);
      else ctx2.lineTo(x + Math.cos(a1) * r, y + Math.sin(a1) * r);
      ctx2.lineTo(x + Math.cos(a2) * r * 0.4, y + Math.sin(a2) * r * 0.4);
    }
    ctx2.closePath();
    ctx2.fill();
  }

  const frontTex = renderFaceTexture('front', 1024);
  const backTex = renderFaceTexture('back', 1024);

  // ─── METALLIC COLOR HELPERS ───────────────────────────────────────
  function getMetalColors(type) {
    switch (type) {
      case 'bronze': return { base: [184, 115, 51], highlight: [230, 190, 120], dark: [80, 50, 20] };
      case 'silver': return { base: [192, 192, 192], highlight: [240, 240, 245], dark: [100, 100, 110] };
      case 'gold':   return { base: [212, 170, 60], highlight: [255, 230, 140], dark: [120, 90, 20] };
      case 'black':  return { base: [30, 30, 50], highlight: [80, 80, 120], dark: [10, 10, 20] };
      default:       return { base: [212, 170, 60], highlight: [255, 230, 140], dark: [120, 90, 20] };
    }
  }

  function lerpColor(a, b, t) {
    return [
      a[0] + (b[0] - a[0]) * t,
      a[1] + (b[1] - a[1]) * t,
      a[2] + (b[2] - a[2]) * t
    ];
  }

  function colorStr(c, a) {
    return `rgba(${Math.round(c[0])},${Math.round(c[1])},${Math.round(c[2])},${a !== undefined ? a : 1})`;
  }

  // ─── RENDER COIN AT GIVEN ANGLES ──────────────────────────────────
  function renderCoin(ctx2, w, h, rotY, rotX, metalType, time) {
    const m = getMetalColors(metalType || 'gold');
    const scale = Math.min(w, h) * 0.42;

    // Transform all points
    const transformed = coinGeo.points.map(p => {
      let [x, y, z] = rotateY(p[0], p[1], p[2], rotY);
      [x, y, z] = rotateX(x, y, z, rotX);
      return [x, y, z];
    });

    // Project (orthographic)
    const projected = transformed.map(p => {
      return [p[0] * scale + w / 2, -p[1] * scale + h / 2, p[2]];
    });

    // Sort faces by depth for painter's algorithm
    function faceDepth(indices) {
      let sumZ = 0;
      indices.forEach(i => { sumZ += transformed[i][2]; });
      return sumZ / indices.length;
    }

    // Collect all drawable faces with depth
    const frontFaces = coinGeo.frontFaceIndices.map((idx, i) => ({
      type: 'front', idx, depth: faceDepth(idx), normal: computeNormal(transformed, idx)
    }));
    const backFaces = coinGeo.backFaceIndices.map((idx, i) => ({
      type: 'back', idx, depth: faceDepth(idx), normal: computeNormal(transformed, idx)
    }));

    // Edge lines (reedes) - draw as thin rectangles
    const edgeLines = coinGeo.edgeIndices.map(([a, b]) => {
      const midZ = (transformed[a][2] + transformed[b][2]) / 2;
      return { a, b, depth: midZ };
    });

    // Sort everything by depth (back to front)
    const allDrawables = [
      ...frontFaces.map(f => ({ kind: 'face', ...f })),
      ...backFaces.map(f => ({ kind: 'face', ...f })),
      ...edgeLines.map(e => ({ kind: 'edge', ...e }))
    ];
    allDrawables.sort((a, b) => a.depth - b.depth);

    // Specular highlight calculation
    const lightDir = normalize3([0.5, 0.7, -0.3]);
    const viewDir = [0, 0, 1];

    for (const item of allDrawables) {
      if (item.kind === 'face') {
        drawFace(ctx2, projected, item.idx, m, lightDir, viewDir, item.normal, scale);
      } else {
        drawEdgeLine(ctx2, projected[item.a], projected[item.b], m, lightDir, viewDir);
      }
    }

    // Specular overlay (glossy sheen)
    drawSpecularOverlay(ctx2, w, h, rotY, rotX, m, scale, time);
  }

  function computeNormal(transformed, indices) {
    const p0 = transformed[indices[0]];
    const p1 = transformed[indices[1]];
    const p2 = transformed[indices[2]];
    const v1 = [p1[0]-p0[0], p1[1]-p0[1], p1[2]-p0[2]];
    const v2 = [p2[0]-p0[0], p2[1]-p0[1], p2[2]-p0[2]];
    return normalize3([
      v1[1]*v2[2] - v1[2]*v2[1],
      v1[2]*v2[0] - v1[0]*v2[2],
      v1[0]*v2[1] - v1[1]*v2[0]
    ]);
  }

  function normalize3(v) {
    const len = Math.sqrt(v[0]*v[0] + v[1]*v[1] + v[2]*v[2]) || 1;
    return [v[0]/len, v[1]/len, v[2]/len];
  }

  function drawFace(ctx2, projected, indices, m, lightDir, viewDir, normal, scale) {
    const pts = indices.map(i => projected[i]);

    // Determine if front or back face based on normal z-component
    const isFront = normal[2] > 0;

    ctx2.save();
    ctx2.beginPath();
    ctx2.moveTo(pts[0][0], pts[0][1]);
    for (let i = 1; i < pts.length; i++) ctx2.lineTo(pts[i][0], pts[i][1]);
    ctx2.closePath();

    // Base metallic color with normal-based shading
    const dotNL = Math.max(0, normal[0] * lightDir[0] + normal[1] * lightDir[1] + normal[2] * lightDir[2]);
    const shade = 0.35 + dotNL * 0.65;

    // Texture mapping (simplified - use face center for texture lookup)
    const cx = (pts[0][0] + pts[1][0] + pts[2][0]) / 3;
    const cy = (pts[0][1] + pts[1][1] + pts[2][1]) / 3;

    // Draw textured version using image data
    if (isFront) {
      ctx2.drawImage(frontTex, cx - scale * 0.5, cy - scale * 0.5, scale, scale);
    } else {
      ctx2.drawImage(backTex, cx - scale * 0.5, cy - scale * 0.5, scale, scale);
    }

    // Metallic overlay
    const baseColor = lerpColor(m.dark, m.highlight, shade);
    ctx2.globalCompositeOperation = 'multiply';
    ctx2.fillStyle = colorStr(baseColor);
    ctx2.fill();

    ctx2.restore();
  }

  function drawEdgeLine(ctx2, p0, p1, m, lightDir, viewDir) {
    const dx = p1[0] - p0[0];
    const dy = p1[1] - p0[1];
    const len = Math.sqrt(dx*dx + dy*dy);
    if (len < 0.5) return;

    // Edge shading based on angle to light
    const nx = -dy / len;
    const ny = dx / len;
    const dotN = Math.abs(nx * lightDir[0] + ny * lightDir[1]);
    const shade = 0.3 + dotN * 0.5;

    ctx2.save();
    ctx2.beginPath();
    ctx2.moveTo(p0[0], p0[1]);
    ctx2.lineTo(p1[0], p1[1]);
    ctx2.strokeStyle = colorStr(lerpColor(m.dark, m.highlight, shade), 0.8);
    ctx2.lineWidth = Math.max(1, len * 0.04);
    ctx2.stroke();
    ctx2.restore();
  }

  function drawSpecularOverlay(ctx2, w, h, rotY, rotX, m, scale, time) {
    // Calculate specular highlight position based on rotation
    const specAngle = rotY * 0.5 + time * Math.PI * 2;
    const hx = Math.cos(specAngle) * scale * 0.35 + w / 2;
    const hy = Math.sin(rotX) * scale * 0.15 + h / 2 - scale * 0.1;

    // Raking specular highlight
    const grad = ctx2.createRadialGradient(hx, hy, 0, hx, hy, scale * 0.6);
    grad.addColorStop(0, colorStr(m.highlight, 0.35));
    grad.addColorStop(0.4, colorStr(m.highlight, 0.12));
    grad.addColorStop(1, 'rgba(0,0,0,0)');

    ctx2.save();
    // Clip to coin shape
    ctx2.beginPath();
    ctx2.ellipse(w / 2, h / 2, scale * 1.02, scale * 1.02, 0, 0, Math.PI * 2);
    ctx2.clip();

    ctx2.fillStyle = grad;
    ctx2.fillRect(0, 0, w, h);

    // Secondary highlight (environment reflection)
    const hx2 = w / 2 - Math.cos(specAngle + 1.5) * scale * 0.25;
    const hy2 = h / 2 + Math.sin(rotX + 0.8) * scale * 0.1;
    const grad2 = ctx2.createRadialGradient(hx2, hy2, 0, hx2, hy2, scale * 0.3);
    grad2.addColorStop(0, colorStr(m.highlight, 0.15));
    grad2.addColorStop(1, 'rgba(0,0,0,0)');
    ctx2.fillStyle = grad2;
    ctx2.fillRect(0, 0, w, h);

    ctx2.restore();
  }

  // ─── ANIMATION STATE ──────────────────────────────────────────────
  let animTime = 0;
  let animating = true;
  let lastFrame = performance.now();

  function getLoopState(t) {
    // t in [0,1] maps to full rotation cycle
    const ty = t * Math.PI * 2;        // Y-axis rotation (full spin)
    const tx = Math.sin(t * Math.PI) * Math.PI; // X-axis flip (shows both faces)
    return { rotY: ty, rotX: tx };
  }

  function renderFrame(now) {
    if (!animating) return;
    const dt = (now - lastFrame) / 1000;
    lastFrame = now;
    animTime += dt * 0.25; // ~4 seconds per loop
    drawHero(animTime);
    requestAnimationFrame(renderFrame);
  }

  function drawHero(time) {
    const state = getLoopState((time % 1));
    ctx.clearRect(0, 0, W, H);
    renderCoin(ctx, W, H, state.rotY, state.rotX, 'gold', time);
  }

  // ─── PUBLIC API ───────────────────────────────────────────────────
  window.demo = {
    canvas: HERO,

    setTime(t) {
      t = ((t % 1) + 1) % 1;
      const state = getLoopState(t);
      ctx.clearRect(0, 0, W, H);
      renderCoin(ctx, W, H, state.rotY, state.rotX, 'gold', t * 100);
    },

    pause() {
      animating = false;
    }
  };

  // Start animation
  requestAnimationFrame(renderFrame);

  // ─── EDITION COINS ────────────────────────────────────────────────
  const editionTypes = ['bronze', 'silver', 'gold', 'black'];
  const editionStates = ['available', 'sold-out', 'coming-soon', 'coming-soon'];

  function drawEditionCoin(canvas, type, state) {
    if (!canvas.width || !canvas.height) return;
    const ectx = canvas.getContext('2d');
    const w = canvas.width;
    const h = canvas.height;

    // Background
    ectx.fillStyle = '#0d0d14';
    ectx.fillRect(0, 0, w, h);

    // Subtle glow behind coin
    const glowGrad = ectx.createRadialGradient(w/2, h/2, w*0.2, w/2, h/2, w*0.5);
    glowGrad.addColorStop(0, 'rgba(212,168,83,0.06)');
    glowGrad.addColorStop(1, 'rgba(0,0,0,0)');
    ectx.fillStyle = glowGrad;
    ectx.fillRect(0, 0, w, h);

    // Draw coin at a slight angle (showing both faces partially)
    const rotY = -0.4;
    const rotX = 0.15;
    renderCoin(ectx, w, h, rotY, rotX, type, performance.now() / 2000);

    // Dim overlay for sold-out / coming-soon
    if (state === 'sold-out' || state === 'coming-soon') {
      ectx.save();
      ectx.globalAlpha = 0.5;
      ectx.fillStyle = '#000';
      ectx.fillRect(0, 0, w, h);
      ectx.restore();
    }

    // "SOLD OUT" stamp
    if (state === 'sold-out') {
      ectx.save();
      ectx.translate(w/2, h/2);
      ectx.rotate(-0.3);
      ectx.font = `bold ${w * 0.14}px Georgia, serif`;
      ectx.textAlign = 'center';
      ectx.textBaseline = 'middle';
      ectx.strokeStyle = 'rgba(255,80,80,0.7)';
      ectx.lineWidth = w * 0.01;
      ectx.strokeText('SOLD OUT', 0, 0);
      ectx.fillStyle = 'rgba(255,80,80,0.8)';
      ectx.fillText('SOLD OUT', 0, 0);
      ectx.restore();
    }

    // "COMING SOON" stamp
    if (state === 'coming-soon') {
      ectx.save();
      ectx.translate(w/2, h/2);
      ectx.rotate(0.2);
      ectx.font = `bold ${w * 0.1}px Georgia, serif`;
      ectx.textAlign = 'center';
      ectx.textBaseline = 'middle';
      ectx.strokeStyle = 'rgba(107,159,255,0.6)';
      ectx.lineWidth = w * 0.008;
      ectx.strokeText('COMING SOON', 0, 0);
      ectx.fillStyle = 'rgba(107,159,255,0.7)';
      ectx.fillText('COMING SOON', 0, 0);
      ectx.restore();
    }
  }

  // Draw all edition coins
  const editions = document.querySelectorAll('.edition');
  editions.forEach((el, i) => {
    const canvas = el.querySelector('.edition-canvas');
    const type = el.dataset.edition;
    const state = el.dataset.state;
    drawEditionCoin(canvas, type, state);
  });

  // Handle resize
  window.addEventListener('resize', () => {
    resizeHero();
    resizeEditions();
    editions.forEach((el, i) => {
      const canvas = el.querySelector('.edition-canvas');
      drawEditionCoin(canvas, el.dataset.edition, el.dataset.state);
    });
  });

})();
</script>
